INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "お！\nあそこに困ってそうな人発見！", "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, 2, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1001, 0, 1, 0, 1, "春咲 ひより", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "大切な人を\n守れるようになりたい…って", "みんなみたいに\nわたしも強くならなきゃ", 0, 2, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1002, 0, 1, 0, 1, "草野 優衣", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "キミに必要な集中力と感性が", "フェンシングを始めてみては？", 0, 2, "少しは磨かれると思いますよ。", 1003, 0, 1, 0, 1, "士条 怜", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "今日はなにして遊ぶ？", "ねぇ、にいちゃん！", 0, 2, "みそぎはねぇ、\nかくれんぼやりたい！", 1004, 0, 1, 0, 1, "穂高 みそぎ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "ねぇ…", "風宮あかりです", 0, 2, "私といっしょに…\nいかない？", 1006, 0, 1, 0, 1, "風宮 あかり", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "プリンたべたいのー", "出雲宮子なのー", 0, 2, "食べ物の恨みは怖いのー", 1007, 0, 1, 0, 1, "出雲 宮子", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "キミもボクの美貌に\n吸い寄せられたんだね。", "ボクは虹村雪。", 0, 2, "いいよ。\n見られることは運命さ…", 1008, 0, 1, 0, 1, "虹村 雪", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", "フッ…聞いて後悔するがいい！", 0, 2, "人呼んで「疾風の冥姫」!!", 1009, 0, 1, 0, 1, "柊杏奈", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", "マホマホ王国のプリンセス、\nまほ姫どす", 0, 2, "ほんまおおきにやわ～♪", 1010, 0, 1, 0, 1, "姫宮 真歩", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "生き別れたお兄ちゃんを探して\n三千世界！", "衣之咲璃乃です！", 0, 2, "ここで会ったが\n100年目～！", 1011, 0, 1, 0, 1, "衣之咲 璃乃", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "ち、超能力って…\n何のことかな～？", "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, 2, "…って、お願い！\n誰にも言わないでおいて～！", 1012, 0, 1, 0, 1, "柏崎 初音", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "一応カリスマ読モJKやってまっす！", "ちょす！\n美波鈴奈だよ～♪", 0, 2, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1016, 0, 1, 0, 1, "美波 鈴奈", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "東京は遊園地みたいなところさー", "はいたーい。\n喜屋武香織さー。", 0, 2, "でも、沖縄もとってもいいとこさー", 1017, 0, 1, 0, 1, "喜屋武 香織", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "先生って呼ばれるのは\nくすぐったいから", "支倉伊緒です。", 0, 2, "イオちゃんって呼んでね。", 1018, 0, 1, 0, 1, "支倉 伊緒", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "あ！/\お兄ちゃ～ん\nまってよ～", "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, 2, "ミミをおいてかないでぇ～", 1020, 0, 1, 0, 1, "茜 ミミ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "あの……\nふぇ……", "あ…あの…えっと…\n栗…林…くるみ…です……", 0, 2, "ふぇぇぇぇぇん……", 1021, 0, 1, 0, 1, "栗林 くるみ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "こんな私に貴重な時間を\n割いていただき、", "風宮よりです。\nあああああ！", 0, 2, "なんてありがとうございます！", 1022, 0, 1, 0, 1, "風宮 より", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "おにいちゃんどこいくの？\nえ？", "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, 2, "私こっち行きたいー\nね、早く早くー", 1023, 0, 1, 0, 1, "北条 綾音", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "ふ、不束者ですが\nどうぞ末永く…って、", "わっ…わっ…私、\n天野すずめといいます！", 0, 2, "これて何か違う…\nあああすみません！", 1025, 0, 1, 0, 1, "天野 すずめ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "あなたは…運命の……\n伴侶……", "……クスクス…私は\n…倉石恵理子……", 0, 2, "離しませんわ………\n絶対に…!!", 1027, 0, 1, 0, 1, "倉石 恵理子", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, 2, "…そうでしょ？？", 1028, 0, 1, 0, 1, "佐々木 咲恋", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "ぇっと…\nキミ、私のこと知らないの?!", "桜井望だよ！\nよろしくねっ", 0, 2, "あはは、\n私もまだまだだなぁ～", 1029, 0, 1, 0, 1, "桜井 望", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "初めまして、\n私はニノン・ジュベール申すデス！", "デケデケデンっ！", 0, 2, "ショーグン、\nワタシと一緒に天下統一デース！", 1030, 0, 1, 0, 1, "ニノン・ジュベール", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "でもって私の隣にいるのが……\nえ、見えない？", "上喜しのぶです。\n手元のドクロが父です。", 0, 2, "おかしいですね……", 1031, 0, 1, 0, 1, "上喜 しのぶ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "けんども\nそれには足りないモンが…", "目指すはビッグな\nお笑い芸人だっぺ！", 0, 2, "そう、\nオラのボケに突っ込める相方が…！", 1033, 0, 1, 0, 1, "野戸まひる", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "ちょっと緊張しちゃって…", "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, 2, "ちょ\nちょっと一杯飲んできます…！", 1034, 0, 1, 0, 1, "綾瀬 ゆかり", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "知らない人とは話しちゃいけないので", "氷川鏡華…です", 0, 2, "これ以上お話しすることは…\nないです！", 1036, 0, 1, 0, 1, "氷川 鏡華", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "……あ、アラーム。", "柏崎…栞です。", 0, 2, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1038, 0, 1, 0, 1, "柏崎 栞", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "私、一人も友達がいなくて……", "ふ、双葉碧です。", 0, 2, "野に咲く花が、\n唯一の話相手です。", 1040, 0, 1, 0, 1, "双葉 碧", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", "三角千歌です。", 0, 2, "そう思っています。", 1042, 0, 1, 0, 1, "三角 千歌", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "あぁ？\nお前のそいつの仲間か？", "安芸真琴だ。", 0, 2, "う、疑ってすまなかったな…", 1043, 0, 1, 0, 1, "安芸 真琴", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "生けとし生ける全ての者よ！", "わらわこそは夜を総べる者！", 0, 2, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1044, 0, 1, 0, 1, "イリヤ・オーンスタイン", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "ぐふふふふ……はっ！", "そこで騎士は妖精を乱暴に……", 0, 2, "ｌク、クウカに何かご用ですか!?", 1045, 0, 1, 0, 1, "遠見 空花", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "自由気ままで♪\n寝て遊んで、食べてケンカして…", "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, 2, "う～ん…\n猫ってホントに最高にゃ～♪", 1046, 0, 1, 0, 1, "宮坂たまき", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "それでは早速クエストに…", "大神美冬よ！", 0, 2, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1048, 0, 1, 0, 1, "大神 美冬", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "クエストもバトルも\n掃除も洗濯も", "星野静流だよ！", 0, 2, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1049, 0, 1, 0, 1, "星野静流", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "見ての通りの\nセクシー美少女で", "アタシは玉泉美咲。", 0, 2, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1050, 0, 1, 0, 1, "玉泉美咲", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.4, "？？？？", "？？？", 0, 2, "？？？？", 1052, 0, 1, 0, 1, "リマ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 0, 2, "そ、そこまでいうなら\nもらってやる", 1053, 0, 1, 0, 1, "モニカ・ヴァイスヴィント", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 0, 2, "そ、そこまでいうなら\nもらってやる", 1058, 0, 1, 0, 1, "ペコリーヌ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 0, 2, "そ、そこまでいうなら\nもらってやる", 1059, 0, 1, 0, 1, "コッコロ", 0, 1, 0);
INSERT INTO `v1_c81bd78f7cc32a9f358d712c5da9d85f378921524258733d98c3b8aae1323a69` VALUES (1.5, "菓子でつろうなどと\n稚拙な策を……", "モニカ・ヴァイスヴィントだ。", 0, 2, "そ、そこまでいうなら\nもらってやる", 1060, 0, 1, 0, 1, "キャル", 0, 1, 0);
